#include <iostream>
#include <vector>
#include <deque>
using namespace std;

int x;
char c;
vector <char> op;
deque <int> q;

int main()
{
    cin >> x;
    q.push_back(x);
    while (cin >> c >> x)
    {
        if (c=='*' || c=='/')
        {
            x = c=='*'? x*q.back() : q.back()/x;
            q.pop_back();
            q.push_back(x);
        } else
        {
            op.emplace_back(c);
            q.push_back(x);
        }
    }
    x = q.front();
    for (auto p : op)
    {
        q.pop_front();
        x = p=='+'? x+q.front() : x-q.front(); 
    }
    cout << x;
    return 0;
}
